{"content": "import { MetadataRoute } from 'next'

const BASE_URL = 'https://nexa.paragu-ai.com'
const LOCALES = ['es', 'en', 'nl', 'de']
const PAGES = ['home', 'programas', 'nosotros', 'contacto', 'blog', 'faq', 'glosario']

export default function sitemap(): MetadataRoute.Sitemap {
  const entries: MetadataRoute.Sitemap = []
  for (const locale of LOCALES) {
    for (const page of PAGES) {
      entries.push({
        url: `${BASE_URL}/${locale}/${page === 'home' ? '' : page}`,
        lastModified: new Date(),
        changeFrequency: 'monthly',
        priority: page === 'home' ? 1.0 : 0.8,
        alternates: {
          languages: Object.fromEntries(LOCALES.map(l => [l, `${BASE_URL}/${l}/${page === 'home' ? '' : page}`])),
        },
      })
    }
  }
  return entries
}
