  'page-hero': dynamic(() => import('./sections-extra').then(m => ({ default: m.PageHeroSection })), { ssr: true }),
  highlights: dynamic(() => import('./sections-extra').then(m => ({ default: m.HighlightSection })), { ssr: true }),
