export function TaxCalculatorSection({ pageContent }: SectionComponentProps) {
  const c = pageContent.taxCalculator || {}
  const [income, setIncome] = React.useState('')
  const [sourceCountry, setSourceCountry] = React.useState('netherlands')
  const [showResult, setShowResult] = React.useState(false)
  if (!c.title) return null
  const taxRates: Record<string, {name: string, rate: number}> = {
    netherlands: {name: 'Países Bajos / Nederland', rate: 49.5},
    belgium: {name: 'Bélgica / België', rate: 53.5},
    germany: {name: 'Alemania / Deutschland', rate: 47.5},
    uk: {name: 'Reino Unido / UK', rate: 45},
    spain: {name: 'España', rate: 47},
    us: {name: 'Estados Unidos / USA', rate: 37},
  }
  const pi = parseFloat(income) || 0
  const eu = sourceCountry ? Math.round(pi * (taxRates[sourceCountry].rate / 100)) : 0
  const py = Math.round(pi * 0.10)
  const sv = eu - py
  const sr = pi > 0 ? Math.round((sv / eu) * 100) : 0
  return (
    <section className="py-24 bg-primary text-white">
      <div className="max-w-[600px] mx-auto text-center px-4">
        <h2 className="text-[clamp(1.4rem,2.5vw,2rem)] font-bold mb-2">{c.title}</h2>
        <p className="text-accent text-base mb-6">{c.subtitle}</p>
        <div className="p-8 bg-white/10 rounded-lg">
          <div className="mb-4">
            <label className="block mb-2 font-semibold text-left">{c.incomeLabel || 'Ingreso anual (USD)'}</label>
            <input type="number" value={income} onChange={e => { setIncome(e.target.value); setShowResult(false) }}
              placeholder="100,000"
              className="w-full p-3 rounded-lg text-white text-base"
              style={{ border: '1px solid rgba(255,255,255,0.2)', background: 'rgba(255,255,255,0.1)' }} />
          </div>
          <div className="mb-6">
            <label className="block mb-2 font-semibold text-left">{c.countryLabel || 'País de origen'}</label>
            <select value={sourceCountry} onChange={e => { setSourceCountry(e.target.value); setShowResult(false) }}
              className="w-full p-3 rounded-lg text-white text-base"
              style={{ border: '1px solid rgba(255,255,255,0.2)', background: 'rgba(255,255,255,0.1)' }}>
              {Object.entries(taxRates).map(([k, v]) => (
                <option key={k} value={k} className="bg-primary text-white">{v.name}</option>
              ))}
            </select>
          </div>
          <button onClick={() => setShowResult(true)}
            className="w-full py-3 px-8 bg-accent text-primary font-bold text-base rounded-full cursor-pointer mb-4 border-none hover:opacity-90">
            {c.ctaText || 'Calcular ahorro'}
          </button>
          {showResult && pi > 0 && (
            <div>
              <div className="p-4 rounded-lg mb-3" style={{ background: 'rgba(201,169,110,0.15)' }}>
                <p className="text-accent font-bold text-lg mb-1">{c.yourSavings || 'Tu ahorro estimado:'} <span className="text-xl">${sv.toLocaleString()}/año</span></p>
                <p className="opacity-80 text-xs">{sr}% {c.lessTax || 'menos en impuestos'} — {c.comparisonText || `Pagarías $${eu.toLocaleString()} en ${taxRates[sourceCountry]?.name.split('/')[0]} vs $${py.toLocaleString()} en Paraguay`}</p>
              </div>
              <p className="opacity-50 text-xs mt-2">{c.disclaimer || '* Estimación basada en tasas impositivas marginales máximas. Consulta con un asesor fiscal.'}</p>
            </div>
